DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextForm.pl",
  "parserGraphTool.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context()->noreduce('(-x)-y','(-x)+y');
$r = list_random(-5..-1,1..5);
do {
  $s = ($r % 2)
    ? random(-5, 5, 2)
    : non_zero_random(-4,4,2);
} until (abs($r) != abs($s));
$f = Formula("-x^2 + ($r + $s) x - $r*$s")->reduce;
Context("Point");
$hi = List(Point("($r,0)"), Point("($s,0)"));
$vi = Point("(0,-$r*$s)");
$vx = Point(($r+$s)/2, $f->eval(x => ($r+$s)/2));
$gt = GraphTool(
    "{quadratic,solid,$vi,($r,0),($s,0)}"
)->with(
    availableTools => ["QuadraticTool"],
    showInStatic => 0,
    bBox => [
      -10,
      max(10,-$r*$s+2,($vx->value)[1]+1),
      10,
      min(-10,-$r*$s-2,($vx->value)[1]-1)
    ]
);

############################################################
# Body
############################################################

BEGIN_PGML
Find the quadratic function's horizontal and vertical intercepts. Find the vertex. Use these points to sketch a graph the function.

[`f(x) = [$f]`]

[@KeyboardInstructions('Enter the horizontal intercepts here.')@]**

[_]{$hi}{16}

[@KeyboardInstructions('Enter the vertical intercept here.')@]**

[_]{$vi}{16}

[@KeyboardInstructions('Enter the vertex coordinates here.')@]**

[_]{$vx}{16}

[@KeyboardInstructions('Make a plot of the function.')@]**

[_]{$gt}{11}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
